INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-01', 'Build governed lakehouse pipeline outputs with contract, quality, and lineage evidence', 'Cluster covers onboarding source profiling, lineage registration, quality control, reconciliation, and exception evidence required to produce trusted bronze-to-silver data outputs.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-02', 'Publish governed gold data products for BI and model consumers', 'Cluster covers translating metric definitions, joining curated data, reconciling values, registering assets, and packaging consumer-ready query patterns.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-03', 'Stabilize streaming data contracts and pipeline quality controls', 'Cluster covers streaming/schema exceptions, parser updates, controlled replay, quality controls, and governed metadata evidence for reliable data operations.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-04', 'Certify BI reporting and self-service analytics assets with governed metric evidence', 'Cluster covers KPI refresh, filter-context review, certified analytics dataset preparation, and semantic measure selection for trusted business reporting.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-05', 'Produce decision recommendations through optimization and forecast review evidence', 'Cluster covers constraint scenario modeling, feasible optimization output, forecast confidence review, and business override evidence for decision support.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-06', 'Construct leakage-safe predictive feature datasets for model experimentation', 'Cluster covers selecting prediction-aligned sources, building feature datasets, preserving training versions, and preventing leakage before experimentation.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-07', 'Evaluate statistical experiments and cohort effects for decision evidence', 'Cluster covers validity checks, effect interpretation, heterogeneous cohort review, and decision evidence for experimentation outcomes.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-08', 'Train and package deep learning model candidates with evaluation evidence', 'Cluster covers deep learning training evidence, checkpoint/metric tracking, and package preparation for product or production handoff.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-09', 'Evaluate NLP and LLM candidates with task metrics, schema compliance, and failure analysis', 'Cluster covers LLM/NLP metric review, hallucination and unsafe-output failure clustering, schema compliance, and evaluation evidence handoff.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-10', 'Operate canary model releases with versioned rollout and rollback evidence', 'Cluster covers deployment manifests, model package versioning, endpoint telemetry, rollout observation, and rollback decision evidence.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-11', 'Respond to model drift and feature-skew alerts with production action decisions', 'Cluster covers drift alert investigation, distribution evidence review, upstream data change assessment, and production response decisioning.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-12', 'Deploy edge AI inference and convert IoT anomaly signals into maintenance recommendations', 'Cluster covers edge inference compatibility and telemetry confirmation together with sensor anomaly translation into maintenance recommendations.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-13', 'Maintain governed lineage, classification, access, and stewardship controls for data assets', 'Cluster covers lineage dependencies, classifications, retention metadata, owner attestations, entitlement review, and audit-ready governance records.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-14', 'Approve responsible AI deployment through use-case, privacy, fairness, and residual-risk controls', 'Cluster covers AI use-case registration, responsible AI assessment, privacy/sensitive-attribute review, mitigation ownership, and gate decisioning.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-15', 'Test AI security abuse paths and sensitive-output exposure controls', 'Cluster covers prompt, retrieval, tool-use, and data-exposure abuse path testing with security control evidence.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-16', 'Specify GenAI product features with grounding, output contracts, and release boundaries', 'Cluster covers user journey, interaction sequence, grounding constraints, owner readiness, scope alignment, and feature specification publication.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-17', 'Validate human-AI workflows with user evidence, fallback controls, and product change decisions', 'Cluster covers workflow acceptance tests, user edit and trust signals, explanation/control needs, prioritized changes, and readiness evidence.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-18', 'Configure applied industry AI solutions with domain thresholds, SME review, and handoff guidance', 'Cluster covers vertical AI thresholds, business action-path mapping, human specialist deferral rules, and deployment handoff documentation.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-19', 'Design enterprise AI adoption roadmaps with operating model, initiative sequencing, and value metrics', 'Cluster covers transformation roadmap design, candidate initiative inventory, workstream clustering, operating model logic, and value-tracking structure.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-20', 'Control AI-ready training data quality through annotation adjudication and synthetic release evidence', 'Cluster covers label disagreement adjudication, guideline clarification, synthetic dataset generation, fidelity checks, privacy checks, and release limits.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.capability_master (code, name, description, master_sequence, capability_status, primary_riasec, secondary_riasec, work_style_demands) VALUES ('DAI-IND-CAP-21', 'Model and validate semantic knowledge graph relationships for enrichment release', 'Cluster covers entity and relationship modeling, ontology alignment, graph quality review, correction queue creation, and semantic release decisioning.', NULL, 'Approved', NULL, NULL, NULL);
INSERT INTO public.occupations (code, name, description, primary_riasec, secondary_riasec, tertiary_riasec, riasec_code_string, riasec_reason, observable_behaviours, is_active) VALUES ('DAI-ROLE-001', 'Data Engineer', 'Data Engineer — Data Platform Engineering (Data Platform Engineering work in Data Platform & Engineering involving Build governed lakehouse pipeline outputs with contract, quality, and lineage evidence at L1 maturity; skill cluster includes Profile raw source files against bronze landing contract during onboarding with guided support; Reconcile curated data values against source controls and document mismatch decisions with supervised practice; Apply data quality controls to pipeline output and capture exception evidence with supervised practice; bridge focus: Capability-to-practice bridge for L1 Build governed lakehouse pipeline outputs with contract, quality, and lineage evidence.)', 'I', 'C', NULL, 'IC', 'Data Platform Engineering aligns with Investigative interests because data platform engineering involves diagnosing source behavior, structuring pipeline contracts, and maintaining reliable data evidence. The mapped capability level focuses on Guided trigger/intake, validation, and low-risk execution using Profile raw source files against bronze landing contract during onboarding and produce field-level fit notes; Reconcile curated data values against source controls and document mismatch decisions; Apply data quality controls to pipeline output and capture exception evidence..', NULL, TRUE);
